+/*-
+ *-----------------------------------------------------------------------
+ * ParseSysMk --
+ *	Read and parse the builtin rules file (sys.mk)
+ *
+ * Results:
+ *	Nothing.
+ *
+ * Side Effects:
+ *	Same as Parse_File(): dependencies added, variables set, etc.
+ *
+ *-----------------------------------------------------------------------
+ */
+void
+ParseSysMk(void)
+{
+    LstNode	  ln;
+    Lst		  sysMkPath;
+    Boolean	  old_inLine;
+    int		  old_lineno;
+    char	  *old_fname;
+    FILE	  *old_curFILE;
+
+    /* Save parser globals before Parse_File() clobbers them */
+    old_inLine = inLine;
+    old_lineno = lineno;
+    old_fname = fname;
+    old_curFILE = curFILE;
+
+    /* Parse rules from sys.mk */
+    sysMkPath = Lst_Init (FALSE);
+    Dir_Expand (_PATH_DEFSYSMK, sysIncPath, sysMkPath);
+    if (Lst_IsEmpty(sysMkPath))
+	Fatal("make: no system rules (%s).", _PATH_DEFSYSMK);
+    ln = Lst_Find(sysMkPath, (void *)NULL, ReadMakefile);
+    if (ln != NULL)
+	Fatal("make: cannot open %s.", (char *)Lst_Datum(ln));
+
+    /* Restore globals */
+    inLine = old_inLine;
+    lineno = old_lineno;
+    curFILE = old_curFILE;
+    fname = old_fname;
+}

